package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class GsonFieldNamingStrategyTest {

  @Test
  void testFieldNamingStrategy_Default() throws Exception {
    Gson gson = new Gson();

    // Use reflection to get the private fieldNamingStrategy field from Gson instance
    Field field = Gson.class.getDeclaredField("fieldNamingStrategy");
    field.setAccessible(true);
    FieldNamingStrategy strategyFromField = (FieldNamingStrategy) field.get(gson);

    FieldNamingStrategy strategyFromMethod = gson.fieldNamingStrategy();
    assertNotNull(strategyFromMethod);

    // The default strategy should be FieldNamingPolicy.IDENTITY
    assertEquals(FieldNamingPolicy.IDENTITY, strategyFromField);
    assertEquals(FieldNamingPolicy.IDENTITY, strategyFromMethod);
  }
}
